/**
 * TDD tests for PR Label Assigner.
 *
 * Uses Node.js built-in test runner (node:test) and assert module.
 * Red/Green/Refactor: each test block is written before the implementation code.
 *
 * Run with: node --test test_label_assigner.js
 */

const { describe, it } = require("node:test");
const assert = require("node:assert/strict");
const { assignLabels } = require("./label_assigner.js");

// --- Cycle 1: Basic single-rule glob matching ---
describe("Basic glob matching", () => {
  it("should match a file inside a directory glob", () => {
    const rules = [{ pattern: "docs/**", label: "documentation" }];
    const files = ["docs/README.md"];
    const labels = assignLabels(files, rules);
    assert.deepStrictEqual(labels, new Set(["documentation"]));
  });

  it("should return empty set when no rules match", () => {
    const rules = [{ pattern: "docs/**", label: "documentation" }];
    const files = ["src/main.js"];
    const labels = assignLabels(files, rules);
    assert.deepStrictEqual(labels, new Set());
  });
});

